import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name: ");
        String name = scanner.nextLine();

        // Limit the size of user input to prevent buffer overflow
        int maxLength = 10;
        if (name.length() > maxLength) {
            name = name.substring(0, maxLength);
        }

        // Allocate memory dynamically based on user input length
        char[] buffer = new char[name.length()];

        // Copy user input into buffer using safe method
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
